<Stats id="monster-estuarine_worm_estuarine_worm_ahket_form--stats" atts={[32,16,23,1,13,8]} bab={11} cmb={24} cmd={37} cmdP="can't be tripped" feats={[["Improved Critical"," (bite)"],"Improved Initiative","Iron Will","Power Attack",["Skill Focus"," (Perception)"],"Skill Focus (Stealth)"]} skills={{"per":{"b":11},"stl":{"b":8,"x":"+16 in water"},"swim":{"b":19}}} racial="+8 Stealth in water" sq={<><Link to="/umr/amphibious">amphibious</Link>, seasonal transformation</>} />
