<Stats id="monster-fungal_crawler--stats" atts={[14,20,15,2,13,7]} bab={3} cmb={4} cmd={19} cmdP="27 vs. trip" feats={["Improved Initiative","Step Up"]} skills={{"acro":{"b":10,"x":"+14 jumping"},"climb":{"b":10},"per":{"b":6}}} racial="+14 on Acrobatics checks made to jump" />
